            'verify-deployment',
            '--troubleshooting-file',
            '../package.json'
        ], io);
        expect(code).toBe(1);
        expect(verify_deployment_config).toHaveBeenCalledTimes(0);
        expect(io.error).toHaveBeenCalled();
    });
    it('reads --troubleshooting-file inside cwd', async () => {
